+const isPlainObject = (value: unknown): value is Record<string, unknown> =>
+  typeof value === "object" && value !== null && !Array.isArray(value) &&
+  Object.getPrototypeOf(value) === Object.prototype;
+
+const camelCase = (key: string) => key.replace(/-([a-zA-Z0-9])/g, (_, c) => c.toUpperCase());
+
+export function flattenConfig(
+  value: Record<string, unknown>,
+  prefix = "",
+): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  for (const [key, item] of Object.entries(value)) {
+    const name = [prefix, camelCase(key)].filter(Boolean).join(".");
+    if (isPlainObject(item)) Object.assign(result, flattenConfig(item, name));
+    else result[name] = item;
+  }
+  return result;
+}
+
+export function parseRc(content: string): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  for (const line of content.split(/\\r?\
/)) {
+    const trimmed = line.trim();
+    if (!trimmed || trimmed.startsWith("#")) continue;
+    const separator = trimmed.indexOf("=");
+    if (separator === -1) throw new Error(`Invalid RC entry: ${line}`);
+    const key = trimmed.slice(0, separator).trim();
+    let value = trimmed.slice(separator + 1).trim();
+    if (value.startsWith('"') && value.endsWith('"')) value = value.slice(1, -1);
+    else if (value === "true") result[camelCase(key)] = true;
+    else if (value === "false") result[camelCase(key)] = false;
+    else if (value !== "" && /^[-+]?(?:\\d+\\.?\\d*|\\.\\d+)$/.test(value)) result[camelCase(key)] = Number(value);
+    else result[camelCase(key)] = value;
+    if (!(key in result)) result[camelCase(key)] = value;
+  }
+  return result;
